1	/**
2	 * The Reckoner — observer that emits Lattice pulses when commissions stall,
3	 * fail, or when the guild's work queue drains.
4	 *
5	 * A Phase 2 CDC watcher on `clerk/writs`. No persistent state, no config.
6	 * Install = on; uninstall = off.
7	 *
8	 * Three trigger types (D24):
9	 *
10	 *   - `reckoner.writ-stuck`  — a root writ enters `stuck` and the stuck
11	 *     is terminal non-success (clockworks-retry will not requeue it).
12	 *   - `reckoner.writ-failed` — a root writ enters `failed`.
13	 *   - `reckoner.queue-drained` — after any terminal writ transition, the
14	 *     queue has 0 `open` writs and 0 active rigs.
15	 *
16	 * Roots-only (D23): non-root writs never emit stuck/failed pulses; leaf
17	 * cause information is surfaced through the parent's
18	 * Clerk-cascaded resolution (parsed via `parseChildFailures`).
19	 *
20	 * Soft clockworks-retry dependency (D16): the retry cap is resolved at
21	 * emit time via `guild().apparatus<ClockworksRetryApi>('clockworks-retry')`.
22	 * When absent every stuck is terminal from the Reckoner's viewpoint.
23	 *
24	 * See: docs/architecture/apparatus/reckoner.md
25	 */
26	
27	import type { Plugin, StartupContext } from '@shardworks/nexus-core';
28	import { guild } from '@shardworks/nexus-core';
29	import type { ReadOnlyBook, StacksApi } from '@shardworks/stacks-apparatus';
30	import type { WritDoc } from '@shardworks/clerk-apparatus';
31	import type { LatticeApi } from '@shardworks/lattice-apparatus';
32	
33	import { isQueueDrained } from './drain.ts';
34	import {
35	  type SpiderStuckStatus,
36	  isTerminalStuck,
37	  parseChildFailures,
38	  writShortId,
39	} from './predicates.ts';
40	import {
41	  RECKONER_PLUGIN_ID,
42	  TRIGGER_QUEUE_DRAINED,
43	  TRIGGER_WRIT_FAILED,
44	  TRIGGER_WRIT_STUCK,
45	  type QueueDrainedContext,
46	  type ReckonerApi,
47	  type WritFailedContext,
48	  type WritStuckContext,
49	} from './types.ts';
50	
51	/**
52	 * Minimal shape of the clockworks-retry API surface the Reckoner reads.
53	 * Re-declared locally so we do not force a hard dependency on
54	 * `@shardworks/clockworks-retry-apparatus` just to read one field.
55	 */
56	interface MaxAttemptsApi {
57	  readonly maxAttempts: number;
58	}
59	
60	/**
61	 * Minimal shape of a Spider rig row — only `writId` and `status` are read.
62	 * Declared locally to avoid a hard Spider dependency.
63	 */
64	interface RigRow extends Record<string, unknown> {
65	  id: string;
66	  writId: string;
67	  status: string;
68	}
69	
70	/** Resolve the clockworks-retry cap, or undefined if not installed. */
71	function resolveMaxAttempts(): number | undefined {
72	  try {
73	    const api = guild().apparatus<MaxAttemptsApi>('clockworks-retry');
74	    return api?.maxAttempts;
75	  } catch {
76	    return undefined;
77	  }
78	}
79	
80	export function createReckoner(): Plugin {
81	  const triggerTypes = [
82	    TRIGGER_WRIT_STUCK,
83	    TRIGGER_WRIT_FAILED,
84	    TRIGGER_QUEUE_DRAINED,
85	  ] as const;
86	
87	  const api: ReckonerApi = {
88	    source: RECKONER_PLUGIN_ID,
89	    triggerTypes: [...triggerTypes],
90	  };
91	
92	  return {
93	    apparatus: {
94	      // Lattice and Clerk are hard requires — without them the Reckoner
95	      // has nothing to observe or nowhere to emit. Spider and
96	      // clockworks-retry are soft dependencies: Spider owns the rigs
97	      // book the Reckoner reads for retry-cap and drain evaluation;
98	      // clockworks-retry owns the cap constant. Both degrade gracefully:
99	      // no Spider → no rigs book → rigs counts return 0; no
100	      // clockworks-retry → maxAttempts is undefined → every stuck is
101	      // terminal from the Reckoner's viewpoint.
102	      requires: ['clerk', 'lattice', 'stacks'],
103	      recommends: ['spider', 'clockworks-retry', 'oculus'],
104	
105	      provides: api,
106	
107	      async start(_ctx: StartupContext): Promise<void> {
108	        const g = guild();
109	        const stacks = g.apparatus<StacksApi>('stacks');
110	        const lattice = g.apparatus<LatticeApi>('lattice');
111	
112	        // Read-only handles. Spider's rigs book may not exist if Spider
113	        // is not installed — readBook still returns a valid handle but
114	        // find/count calls on it resolve to empty/zero. That is the
115	        // intended degradation path.
116	        const writsBook: ReadOnlyBook<WritDoc> = stacks.readBook<WritDoc>('clerk', 'writs');
117	        const rigsBook: ReadOnlyBook<RigRow> = stacks.readBook<RigRow>('spider', 'rigs');
118	
119	        // Build and emit a stuck pulse for `writ`.
120	        async function emitStuck(writ: WritDoc): Promise<void> {
121	          const spiderStatus = writ.status?.spider as SpiderStuckStatus | undefined;
122	          const context: WritStuckContext = {
123	            writShortId: writShortId(writ.id),
124	            writPhase: 'stuck',
125	            writTitle: writ.title,
126	            writType: writ.type,
127	            ...(typeof spiderStatus?.stuckCause === 'string' ? { stuckCause: spiderStatus.stuckCause } : {}),
128	            ...(typeof spiderStatus?.retryable === 'boolean' ? { retryable: spiderStatus.retryable } : {}),
129	            ...(typeof spiderStatus?.detail === 'string' ? { detail: spiderStatus.detail } : {}),
130	          };
131	          const title = `Writ stuck: ${writ.title}`;
132	          const summaryParts: string[] = [
133	            `${writShortId(writ.id)} ("${writ.title}") is stuck.`,
134	          ];
135	          if (spiderStatus?.stuckCause) {
136	            summaryParts.push(`Cause: ${spiderStatus.stuckCause}.`);
137	          }
138	          if (spiderStatus?.detail) {
139	            summaryParts.push(`Detail: ${spiderStatus.detail}`);
140	          }
141	          const leafFailures = parseChildFailures(writ.resolution);
142	          if (leafFailures.length > 0) {
143	            summaryParts.push(
144	              `Originated from child ${leafFailures.map(writShortId).join(', ')}.`,
145	            );
146	          }
147	          await lattice.emit({
148	            source: RECKONER_PLUGIN_ID,
149	            triggerType: TRIGGER_WRIT_STUCK,
150	            writId: writ.id,
151	            title,
152	            summary: summaryParts.join(' '),
153	            linkUrl: null,
154	            context: context as unknown as Record<string, unknown>,
155	          });
156	        }
157	
158	        // Build and emit a failed pulse for `writ`.
159	        async function emitFailed(writ: WritDoc): Promise<void> {
160	          const childFailures = parseChildFailures(writ.resolution);
161	          const context: WritFailedContext = {
162	            writShortId: writShortId(writ.id),
163	            writTitle: writ.title,
164	            writType: writ.type,
165	            ...(typeof writ.resolution === 'string' ? { resolution: writ.resolution } : {}),
166	            ...(childFailures.length > 0
167	              ? { childFailures: childFailures.map(writShortId) }
168	              : {}),
169	          };
170	          const title = `Writ failed: ${writ.title}`;
171	          const summaryParts: string[] = [
172	            `${writShortId(writ.id)} ("${writ.title}") failed.`,
173	          ];
174	          if (writ.resolution) {
175	            summaryParts.push(`Resolution: ${writ.resolution}`);
176	          }
177	          await lattice.emit({
178	            source: RECKONER_PLUGIN_ID,
179	            triggerType: TRIGGER_WRIT_FAILED,
180	            writId: writ.id,
181	            title,
182	            summary: summaryParts.join(' '),
183	            linkUrl: null,
184	            context: context as unknown as Record<string, unknown>,
185	          });
186	        }
187	
188	        async function emitDrained(lastTerminal: WritDoc): Promise<void> {
189	          const now = new Date().toISOString();
190	          const context: QueueDrainedContext = {
191	            drainedAt: now,
192	            lastTerminalWritId: lastTerminal.id,
193	          };
194	          const title = 'Queue drained';
195	          const summary = `Queue drained after ${writShortId(lastTerminal.id)} ("${lastTerminal.title}") reached a terminal state.`;
196	          await lattice.emit({
197	            source: RECKONER_PLUGIN_ID,
198	            triggerType: TRIGGER_QUEUE_DRAINED,
199	            writId: null,
200	            title,
201	            summary,
202	            linkUrl: null,
203	            context: context as unknown as Record<string, unknown>,
204	          });
205	        }
206	
207	        // ── Observer ────────────────────────────────────────────
208	
209	        stacks.watch<WritDoc>(
210	          'clerk',
211	          'writs',
212	          async (event) => {
213	            // Only react to phase transitions on existing writs.
214	            if (event.type !== 'update') return;
215	            const writ = event.entry;
216	            const prev = event.prev;
217	            if (writ.phase === prev.phase) return;
218	
219	            const enteredStuck = writ.phase === 'stuck' && prev.phase !== 'stuck';
220	            const enteredFailed = writ.phase === 'failed' && prev.phase !== 'failed';
221	            const enteredTerminal =
222	              writ.phase === 'completed' ||
223	              writ.phase === 'failed' ||
224	              writ.phase === 'cancelled';
225	
226	            // Roots-only gate for the per-writ pulses. Children never emit
227	            // their own stuck/failed pulses — their cause surfaces in the
228	            // parent's resolution.
229	            const isRoot = !writ.parentId;
230	
231	            if (isRoot && enteredStuck) {
232	              const spiderStatus = writ.status?.spider as SpiderStuckStatus | undefined;
233	              const maxAttempts = resolveMaxAttempts();
234	              const rigCount = await rigsBook.count([['writId', '=', writ.id]]);
235	              if (isTerminalStuck(spiderStatus, rigCount, maxAttempts)) {
236	                await emitStuck(writ);
237	              }
238	            }
239	
240	            if (isRoot && enteredFailed) {
241	              await emitFailed(writ);
242	            }
243	
244	            // Drain check runs after every terminal transition — even
245	            // non-root ones. The drain predicate is independent of the
246	            // roots-only gate.
247	            if (enteredTerminal) {
248	              const drained = await isQueueDrained(writsBook, rigsBook);
249	              if (drained) {
250	                await emitDrained(writ);
251	              }
252	            }
253	          },
254	          { failOnError: false },
255	        );
256	      },
257	    },
258	  };
259	}
